796	    if (inputs.add_generation_prompt) {
797	        inp["add_generation_prompt"] = true;
798	    }
799	
800	    jinja::global_from_json(ctx, inp, inputs.mark_input);
801	
802	    // render
803	    jinja::runtime runtime(ctx);
804	    const jinja::value results = runtime.execute(tmpl.prog);
